#!/usr/bin/env python3
"""Single-file PS5 Redis 3.00 core escape bundle.

Unpacks its helper modules into .redis_escape_core_bundle and runs the trimmed
core PoC. Public modes intentionally exclude Lapse and UMTX experiments.
"""
import base64
import os
import subprocess
import sys
import zlib
from pathlib import Path

BUNDLED_FILES = {
    'poc_redis_300_native_rop_core.py': '',
    'redis_hll_guarded_probe.py': '',
    'redis_hll_cclosure_leak.py': '',
    'redis_hll_prespray_cclosure_read.py': '',
    'redis_hll_prespray_module_pivot.py': '',
}

def unpack_bundle(base_dir):
    bundle_dir = base_dir / '.redis_escape_core_bundle'
    bundle_dir.mkdir(parents=True, exist_ok=True)
    for name, blob in BUNDLED_FILES.items():
        data = zlib.decompress(base64.b64decode(blob.encode('ascii')))
        path = bundle_dir / name
        if not path.exists() or path.read_bytes() != data:
            path.write_bytes(data)
    return bundle_dir

def main():
    base_dir = Path(__file__).resolve().parent
    bundle_dir = unpack_bundle(base_dir)
    core = bundle_dir / 'poc_redis_300_native_rop_core.py'
    env = os.environ.copy()
    env['PYTHONPATH'] = str(bundle_dir) + os.pathsep + env.get('PYTHONPATH', '')
    return subprocess.call([sys.executable, str(core), *sys.argv[1:]], cwd=str(base_dir), env=env)

if __name__ == '__main__':
    raise SystemExit(main())
